import "./badge.css";

import { cn } from "tailwind-variants";

import { badgeVariants, type BadgeVariants } from "./badge.variants";

export type BadgeProps = BadgeVariants & React.ComponentProps<"span">;

export const Badge = ({ children, className, variant, ...props }: BadgeProps) => {
  return (
    <span className={cn(badgeVariants({ variant }), className)} {...props}>
      {children}
    </span>
  );
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const badgeVariants = tv({
  base: "badge",
  variants: {
    variant: {
      default: "badge--default",
      secondary: "badge--secondary",
      destructive: "badge--destructive",
      outline: "badge--outline",
    },
  },
  defaultVariants: {
    variant: "default",
  },
});

export type BadgeVariants = VariantProps<typeof badgeVariants>;

.badge {
  @apply inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

.badge--default {
  @apply bg-primary text-primary-foreground border-transparent;
}

.badge--secondary {
  @apply bg-secondary text-secondary-foreground border-transparent;
}

.badge--destructive {
  @apply bg-destructive text-white border-transparent;
}

.badge--outline {
  @apply text-foreground;
}

import { Badge, type BadgeProps } from "./badge";
import { type BadgeVariants, badgeVariants } from "./badge.variants";

export { Badge, badgeVariants };

export type { BadgeProps, BadgeVariants };
